// Pull each run's ensures of `remove` into the proof context with explicit
// triggers so z3 can align the two runs.

// Run 1.
assert(r1 == v@);
assert(post1_self_@ =~= pre_self_@.remove_value(r1));
assert(forall|x: T| #![auto] post1_self_@.contains(x) ==>
    pre_self_.get_node_ref(x) == post1_self_.get_node_ref(x));

// Run 2.
assert(r2 == v@);
assert(post2_self_@ =~= pre_self_@.remove_value(r2));
assert(forall|x: T| #![auto] post2_self_@.contains(x) ==>
    pre_self_.get_node_ref(x) == post2_self_.get_node_ref(x));

// The two returns coincide: both equal v@.
assert(r1 == r2);

// `pre_self_@.remove_value(_)` is a function of its second argument, so the
// two right-hand sides of the `=~=` equations above are syntactically equal
// once r1 == r2. Seq extensionality (=~=) then propagates equality of the
// two post views.
assert(pre_self_@.remove_value(r1) == pre_self_@.remove_value(r2));
assert(post1_self_@ =~= post2_self_@);

// On the shared view, `get_node_ref` is preserved from `pre_self_` in each
// run, so the two runs agree element-wise on `get_node_ref`. We trigger
// the post2 ensures via the matching `contains` fact derived from view
// equality.
assert forall|x: T| #![auto] post1_self_@.contains(x) implies
    post1_self_.get_node_ref(x) == post2_self_.get_node_ref(x) by {
    assert(post2_self_@.contains(x));
}
